function solve(words) {
    function computeCommonPrefix(a, b) {
        let minLen = Math.min(a.length, b.length);
        for (let i = 0; i < minLen; i++) {
            if (a[i] !== b[i]) {
                return i;
            }
        }
        return minLen;
    }

    const n = words.length;
    if (n === 0) return [];
    if (n === 1) return [0];

    const max_prefix = new Array(n - 1).fill(0);
    for (let j = 0; j < n - 1; j++) {
        max_prefix[j] = computeCommonPrefix(words[j], words[j + 1]);
    }

    const prefix_max = new Array(n - 1).fill(0);
    prefix_max[0] = max_prefix[0];
    for (let i = 1; i < n - 1; i++) {
        prefix_max[i] = Math.max(prefix_max[i - 1], max_prefix[i]);
    }

    const suffix_max = new Array(n - 1).fill(0);
    suffix_max[n - 2] = max_prefix[n - 2];
    for (let i = n - 3; i >= 0; i--) {
        suffix_max[i] = Math.max(max_prefix[i], suffix_max[i + 1]);
    }

    const answer = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let left_max = 0;
        let right_max = 0;
        let middle = 0;

        if (i > 0) {
            if (i - 2 >= 0) {
                left_max = prefix_max[i - 2];
            }
        }

        if (i < n - 1) {
            if (i + 1 <= n - 2) {
                right_max = suffix_max[i + 1];
            }
        }

        if (i > 0 && i < n - 1) {
            middle = computeCommonPrefix(words[i - 1], words[i + 1]);
        }

        answer[i] = Math.max(left_max, right_max, middle);
    }

    return answer;
}

